                            <div class="form-group">
                                <label for="deviceName">Device Name *</label>
                                <input type="text" id="deviceName" class="form-control" placeholder="e.g., Main Entrance Kiosk" required>
                            </div>
                            
                            <div class="form-group">
                                <label for="deviceId">Device ID *</label>
                                <input type="text" id="deviceId" class="form-control" placeholder="e.g., KIOSK-001" required>
                            </div>
                        </div>
                        
                        <div class="form-row">
                            <div class="form-group">
                                <label for="deviceModel">Device Model</label>
                                <input type="text" id="deviceModel" class="form-control" placeholder="e.g., Samsung Tab A7">
                            </div>
                            
                            <div class="form-group">
                                <label for="location">Location *</label>
                                <input type="text" id="location" class="form-control" placeholder="e.g., Main Lobby" required>
                            </div>
                        </div>
                        
                        <div class="form-group">
                            <label for="faceAuthUrl">Face Auth Service URL *</label>
                            <input type="url" id="faceAuthUrl" class="form-control" placeholder="http://localhost:5000/face-auth" required>
                            <small style="color: var(--text-light); margin-top: 5px; display: block;">URL of the local face authentication service</small>
                        </div>
                        
                        <div class="form-row">
                            <div class="form-group">
                                <label for="syncFrequency">Sync Frequency (minutes)</label>
                                <input type="number" id="syncFrequency" class="form-control" value="15" min="5" max="1440">
                            </div>
                            
                            <div class="form-group">
                                <label for="deviceStatus">Status</label>
                                <select id="deviceStatus" class="form-control">
                                    <option value="active">Active</option>
                                    <option value="inactive">Inactive</option>
                                </select>
                            </div>
                        </div>
                        
                        <div class="form-actions">
                            <button type="button" class="btn-secondary" id="cancelForm">Cancel</button>
                            <button type="submit" class="btn-primary" id="submitForm">Save Device</button>
                        </div>
                    </form>
                </div>
                
                <!-- Sync Logs Tab -->
                <div class="tab-content" v-show="activeTab === 'sync'">
    <div v-for="(log, index) in syncLogs" :key="index"
         class="sync-log-item"
         :class="log.status">
        <strong>{{ log.time }}</strong>
        <p>{{ log.message }}</p>
    </div>
</div>
                
                <!-- Remote Logs Tab -->
                <div class="tab-content" v-show="activeTab === 'remote'">
                    <div class="remote-log-viewer">
                        <h4>Remote Device Logs</h4>
                        <p>Live logs from the selected kiosk device</p>
                        
                        <div class="remote-log-viewer">
        <pre class="remote-log-content">
{{ remoteLogs[selectedDeviceId] }}
        </pre>
    </div>
                        
                        <div class="form-actions" style="border-top: none; margin-top: 20px; padding-top: 0;">
                            <button type="button" class="btn-secondary" id="refreshRemoteLogs">
                                <i class="fas fa-sync-alt"></i> Refresh Logs
                            </button>
                            <button type="button" class="btn-primary" id="downloadLogs">
                                <i class="fas fa-download"></i> Download Logs
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        
             

